import Autumn from 'autumn-js';
import fs from 'fs';

// Initialize Autumn client with secret key from environment
const autumn = new Autumn(process.env.AUTUMN_SECRET_KEY);

// Customer data
const customers = [
  {
    customerId: 'user_test_001',
    name: 'Bob Builder',
    email: 'bob@example.com'
  },
  {
    customerId: 'user_test_002',
    name: 'Carol Coder',
    email: 'carol@example.com'
  }
];

async function onboardCustomers() {
  try {
    console.log('Creating customers in parallel...');

    // Step 1: Create/sync customers in parallel
    const customerPromises = customers.map(customer =>
      autumn.customers.getOrCreate(customer.customerId, {
        name: customer.name,
        email: customer.email
      })
    );

    const createdCustomers = await Promise.all(customerPromises);
    console.log('Customers created:', createdCustomers.map(c => c.id));

    // Step 2: Attach "free" plan to both customers in parallel
    console.log('Attaching free plan to customers in parallel...');
    const attachPromises = customers.map(customer =>
      autumn.attach({
        customerId: customer.customerId,
        productId: 'free'
      })
    );

    const attachResults = await Promise.all(attachPromises);
    console.log('Plans attached successfully');

    // Step 3: Save results to JSON file
    const result = {
      customers: customers.map((customer, index) => ({
        customerId: customer.customerId,
        planAttached: true
      }))
    };

    fs.writeFileSync(
      '/home/user/myproject/onboard_result.json',
      JSON.stringify(result, null, 2)
    );

    console.log('Results saved to onboard_result.json');
    console.log(JSON.stringify(result, null, 2));

  } catch (error) {
    console.error('Error during customer onboarding:', error);
    process.exit(1);
  }
}

// Run the onboarding process
onboardCustomers();

